// ── PROGRAM START DATE ────────────────────────────────────────────────────────
// Set this to the date you want athletes to be able to start workouts.
// Format: "YYYY-MM-DD"  e.g. "2025-05-01" for May 1st 2025
const PROGRAM_START_DATE = "2026-04-05";

function isProgramLive() {
  return new Date() >= new Date(PROGRAM_START_DATE);
}

function daysUntilStart() {
  const diff = new Date(PROGRAM_START_DATE) - new Date();
  return Math.max(0, Math.ceil(diff / 86400000));
}

function formatStartDate() {
  // Use UTC to prevent timezone offset shifting the date
  const [y, m, d] = PROGRAM_START_DATE.split("-").map(Number);
  return new Date(y, m - 1, d).toLocaleDateString("en-CA", {
    weekday: "long", year: "numeric", month: "long", day: "numeric"
  });
}



