function getEarnedAchievements(completedWorkouts, streakDays) {
  return ACHIEVEMENTS.filter(a => {
    try { return a.check(completedWorkouts, streakDays); } catch { return false; }
  }).map(a => a.id);
}

// ── STREAK HELPERS ────────────────────────────────────────────────────────────
function calcStreak(completedWorkouts) {
  const dates = Object.values(completedWorkouts)
    .map(w => w.completedAt ? new Date(w.completedAt).toDateString() : null)
    .filter(Boolean);
  const unique = [...new Set(dates)].map(d => new Date(d)).sort((a, b) => b - a);
  if (!unique.length) return 0;
  let streak = 1;
  const today = new Date().toDateString();
  const yesterday = new Date(Date.now() - 86400000).toDateString();
  const latest = unique[0].toDateString();
  if (latest !== today && latest !== yesterday) return 0;
  for (let i = 1; i < unique.length; i++) {
    const diff = Math.round((unique[i-1] - unique[i]) / 86400000);
    if (diff === 1) streak++;
    else break;
  }
  return streak;
}

// ── PERSONAL BEST HELPERS ─────────────────────────────────────────────────────
function detectPRs(newWeights, oldWeights) {
  const prs = [];
  for (const [key, val] of Object.entries(newWeights)) {
    if (!val) continue;
    const old = oldWeights[key];
    if (!old || parseFloat(val) > parseFloat(old)) {
      // key format: wKey__gX__exIdx__setIdx
      prs.push({ key, weight: parseFloat(val) });
    }
  }
  return prs;
}


