function getSpeedVideo(name) {
  // Try exact match first, then partial
  if (SPEED_VIDEOS[name]) return SPEED_VIDEOS[name];
  const key = Object.keys(SPEED_VIDEOS).find(k => name.toLowerCase().includes(k.toLowerCase()) || k.toLowerCase().includes(name.toLowerCase().split(":").pop().trim()));
  return key ? SPEED_VIDEOS[key] : null;
}

// ── FIELD WORK SECTION DETECTION ──────────────────────────────────────────────
// Groups exercises by their section prefix (e.g. "General Warm-Up:", "Movement Prep:")
function getFieldSection(exName) {
  const prefixes = [
    ["General Warm-Up", "🏃 General Warm-Up"],
    ["Movement Prep", "🤸 Movement Prep"],
    ["Neural Activation", "⚡ Neural Activation"],
    ["Ladder Drills", "⚡ Neural Activation / Ladder Drills"],
    ["Neural Activation / Ladder", "⚡ Neural Activation / Ladder Drills"],
    ["Shuffle Technique", "🔀 Shuffle Technique"],
    ["Cross Over Technique", "🔀 Cross Over Technique"],
    ["Change of Direction", "↔️ Change of Direction"],
    ["Deceleration Skill", "🛑 Deceleration Skill"],
    ["Acceleration Skill", "🚀 Acceleration Skill"],
    ["Speed Coordination", "💨 Speed Coordination"],
    ["Speed Angles 1", "📐 Speed Angles 1"],
    ["Speed Angles 2", "📐 Speed Angles 2"],
    ["Speed Angles 3", "📐 Speed Angles 3"],
    ["Speed:", "⚡ Speed"],
    ["Speed-Endurance", "🏁 Speed-Endurance"],
  ];
  for (const [prefix, label] of prefixes) {
    if (exName.startsWith(prefix)) return label;
  }
  return "📋 General";
}

function stripSectionPrefix(exName) {
  return exName.replace(/^[^:]+:\s*/, "");
}


