function getDailyQuote() {
  const dayOfYear = Math.floor((new Date() - new Date(new Date().getFullYear(), 0, 0)) / 86400000);
  return QUOTES[dayOfYear % QUOTES.length];
}

// ── TEAM CHALLENGE CONFIG ─────────────────────────────────────────────────────
// Weekly team challenge resets each Monday (Monday-based weeks)
function getWeeklyChallenge() {
  const now = new Date();
  // Find the most recent Monday (or today if Monday)
  const day = now.getDay(); // 0=Sun, 1=Mon...6=Sat
  const daysSinceMonday = (day === 0) ? 6 : day - 1;
  const monday = new Date(now);
  monday.setHours(0, 0, 0, 0);
  monday.setDate(now.getDate() - daysSinceMonday);
  // Count weeks since a fixed epoch Monday (Jan 5 2026 = first Monday of 2026)
  const epoch = new Date(2026, 2, 30); // Mar 30 2026 = Monday, calibrated so week of Apr 6 = "1,500 combined XP"
  const weekNum = Math.floor((monday - epoch) / (7 * 24 * 60 * 60 * 1000));
  // Scaled for ~15 athletes, ~8-10 active, ~3-4 workouts each per week
  const challenges = [
    { label: "30 combined S&C workouts",        goal: 30,   type: "workouts" },
    { label: "1,500 combined XP",               goal: 1500, type: "xp" },
    { label: "8 field work sessions",           goal: 8,    type: "fieldwork" },
    { label: "25 combined S&C workouts",        goal: 25,   type: "workouts" },
    { label: "20 dribbling sessions",           goal: 20,   type: "dribble" },
    { label: "20 shooting sessions",            goal: 20,   type: "shooting" },
    { label: "1,000 combined XP",               goal: 1000, type: "xp" },
    { label: "10 field work sessions",          goal: 10,   type: "fieldwork" },
    { label: "15 running sessions",             goal: 15,   type: "running" },
    { label: "35 combined S&C workouts",        goal: 35,   type: "workouts" },
    { label: "25 dribbling sessions",           goal: 25,   type: "dribble" },
    { label: "2,000 combined XP",               goal: 2000, type: "xp" },
    { label: "25 shooting sessions",            goal: 25,   type: "shooting" },
    { label: "12 field work sessions",          goal: 12,   type: "fieldwork" },
    { label: "20 running sessions",             goal: 20,   type: "running" },
    { label: "1,500 combined XP",               goal: 1500, type: "xp" },
  ];
  return challenges[weekNum % challenges.length];
}

