// ── CYCLE 2 PROGRAMS ──────────────────────────────────────────────────────────
// All cycle 2 programs unlock when the full cycle 1 of that program is done.
// Each cycle 2 has a banner note shown at the top of the workout view.

// Helper: is a full program (all phases, gym days only) complete?
function isProgramComplete(prog, completedWorkouts) {
  return prog.phases.every(ph =>
    ph.days.every(d => !!completedWorkouts[`${prog.id}__${ph.id}__${d.id}`])
  );
}

