// ── CYCLE 2 UNLOCK HELPERS ────────────────────────────────────────────────────
function isC2Unlocked(cycleOneProg, completedWorkouts, config) {
  // If coach set a manual Cycle 2 start date, check that first
  if (config && config.c2ManualDate && config.c2StartDate) {
    return new Date() >= new Date(config.c2StartDate) && isProgramComplete(cycleOneProg, completedWorkouts);
  }
  return isProgramComplete(cycleOneProg, completedWorkouts);
}

