// ── LOCK HELPERS ──────────────────────────────────────────────────────────────

// Phase unlocked if it's the first, or all days in the previous phase are done
function isPhaseUnlocked(prog, phaseIndex, completedWorkouts, coachBypass = false) {
  if (coachBypass) return true;
  if (phaseIndex === 0) return true;
  const prevPhase = prog.phases[phaseIndex - 1];
  // All gym days must be complete
  const gymDone = prevPhase.days.every(d => !!completedWorkouts[`${prog.id}__${prevPhase.id}__${d.id}`]);
  if (!gymDone) return false;
  // All field work must be complete (per-week keys)
  if (prevPhase.fieldWork && prevPhase.fieldWork.length > 0) {
    const numWeeks = 4;
    for (let w = 1; w <= numWeeks; w++) {
      for (let fi = 0; fi < prevPhase.fieldWork.length; fi++) {
        const fw = prevPhase.fieldWork[fi];
        if (fw.type === "none") continue; // Phase 1 has no linear
        const fwKey = `${prog.id}__${prevPhase.id}__field_${fw.type}_w${w}`;
        if (!completedWorkouts[fwKey]) return false;
      }
    }
  }
  return true;
}

// Day unlocked if it's the first, or the previous day is done
function isDayUnlocked(prog, phase, dayIndex, completedWorkouts, coachBypass = false) {
  if (coachBypass) return true;
  // Dribbling and shooting are always fully unlocked — drills can be repeated freely
  if (prog.id === "dribble" || prog.id === "shooting" || prog.id === "dribble_c2" || prog.id === "shooting_c2") return true;
  if (dayIndex === 0) return true;
  const prevDay = phase.days[dayIndex - 1];
  return !!completedWorkouts[`${prog.id}__${phase.id}__${prevDay.id}`];
}

// Running program unlocks when SC Phase 1 (April / id:"may") is fully complete
function isRunningUnlocked(completedWorkouts) {
  const scMay = SC_PROGRAM.phases.find(p => p.id === "may");
  if (!scMay) return false;
  // All gym days must be done
  if (!scMay.days.every(d => !!completedWorkouts[`sc__may__${d.id}`])) return false;
  // All field work (lateral only, 4 weeks) must be done
  for (let w = 1; w <= 4; w++) {
    if (!completedWorkouts[`sc__may__field_lateral_w${w}`]) return false;
  }
  return true;
}

