async function sbGet(key) {
  try {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/wildcats_data?key=eq.${encodeURIComponent(key)}&select=value`, {
      headers: { "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}` }
    });
    const rows = await res.json();
    return rows && rows.length > 0 ? rows[0].value : null;
  } catch { return null; }
}

async function sbSet(key, value) {
  try {
    await fetch(`${SUPABASE_URL}/rest/v1/wildcats_data`, {
      method: "POST",
      headers: {
        "apikey": SUPABASE_KEY,
        "Authorization": `Bearer ${SUPABASE_KEY}`,
        "Content-Type": "application/json",
        "Prefer": "resolution=merge-duplicates"
      },
      body: JSON.stringify({ key, value, updated_at: new Date().toISOString() })
    });
  } catch(e) { console.error("Supabase set error", e); }
}

async function loadData(key, shared = false) {
  try {
    if (shared) {
      const val = await sbGet(key);
      return val !== null ? val : null;
    } else {
      const val = localStorage.getItem(`wildcats_${key}`);
      return val ? JSON.parse(val) : null;
    }
  } catch { return null; }
}

async function saveData(key, value, shared = false) {
  try {
    if (shared) {
      if (value === null) {
        // Delete from Supabase
        await fetch(`${SUPABASE_URL}/rest/v1/wildcats_data?key=eq.${encodeURIComponent(key)}`, {
          method: "DELETE",
          headers: { "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}` }
        });
      } else {
        await sbSet(key, value);
      }
    } else {
      if (value === null) {
        localStorage.removeItem(`wildcats_${key}`);
      } else {
        localStorage.setItem(`wildcats_${key}`, JSON.stringify(value));
      }
    }
  } catch(e) { console.error("Save error", e); }
}


