  // ── RELOCK / REMOVE XP HELPERS ────────────────────────────────────────────────
  const relockPhaseForAthlete = async (athlete, prog, phase) => {
    const phaseKey = `${prog.id}__${phase.id}`;
    const newCW = { ...athlete.completedWorkouts };
    let xpToRemove = 0;
    phase.days.forEach(d => {
      const k = `${phaseKey}__${d.id}`;
      if (newCW[k]) {
        if (!newCW[k].noXP) xpToRemove += 50;
        delete newCW[k];
      }
    });
    (phase.fieldWork || []).forEach((fw, fi) => {
      const k = `${phaseKey}__field_${fi}`;
      if (newCW[k]) {
        if (!newCW[k].noXP) xpToRemove += 50;
        delete newCW[k];
      }
    });
    const newXP = Math.max(0, (athlete.xp || 0) - xpToRemove);
    const users = (await loadData("wildcats:users", true)) || {};
    if (users[athlete.email]) {
      users[athlete.email].completedWorkouts = newCW;
      users[athlete.email].xp = newXP;
      await saveData("wildcats:users", users, true);
      await saveData(`wildcats:lb:${athlete.email}`, { email: athlete.email, name: athlete.name, xp: newXP }, true);
    }
    setCoachData(prev => prev.map(a => a.email === athlete.email ? { ...a, completedWorkouts: newCW, xp: newXP } : a));
  };

