        const prog = [...ALL_PROGRAMS, SC_PROGRAM_C2, DRIBBLING_PROGRAM_C2, SHOOTING_PROGRAM_C2, RUNNING_PROGRAM, RUNNING_PROGRAM_C2].find(p => p.id === progId);
